import React from 'react';
import PageHeader from '../components/PageHeader/PageHeader';
import MemberCard from '../components/MemberCard/MemberCard';
import './MembersPage.css';

const MembersPage = () => {
  const founder = {
    role: '✦ Temple Founder — In Eternal Memory ✦',
    emoji: '🙏',
    name: 'Late Pandit Tilakdhari Upadhyay',
    description: 'The visionary founder of Shree Ram Janaki Mandir, Late Pandit Tilakdhari Upadhyay consecrated this sacred space through unwavering devotion and spiritual wisdom. His blessing continues to guide every soul who enters this holy abode. His life was a living example of surrender to the divine will of Lord Ram — a legacy that endures forever in the hearts of the devotee community he created.'
  };

  const members = [
    {
      role: 'Temple Owner',
      emoji: '🏛️',
      name: 'Pandit Devendra Upadhyay',
      description: 'The current custodian of the temple, Pandit Devendra Upadhyay continues the sacred mission of his predecessors with devotion and care, ensuring the temple remains a vibrant center of worship and community service.'
    },
    {
      role: 'Late Priest — In Memory',
      emoji: '🪔',
      name: 'Mahant Suresh Das',
      description: 'The late and revered previous priest of the mandir, Mahant Suresh Das dedicated his life to performing the sacred rituals of the temple. His deep knowledge of the scriptures and his loving nature left an indelible mark on the temple\'s spiritual character.'
    },
    {
      role: 'General Manager',
      emoji: '⚙️',
      name: 'Mr. Suyash Upadhyay',
      description: 'The General Manager of Shree Ram Janaki Mandir, Suyash Upadhyay oversees the day-to-day administration and management of the temple\'s operations, ensuring smooth coordination between all activities and the smooth running of temple affairs.'
    },
    {
      role: 'Current Priest',
      emoji: '🌸',
      name: 'Mahant Sarvesh Upadhyay',
      description: 'A devoted priest of the mandir, Mahant Sarvesh Upadhyay brings deep spiritual knowledge and gentle guidance to the daily puja and rituals, nurturing the connection between the devotees and the divine.'
    },
    {
      role: 'Current Priest',
      emoji: '🌼',
      name: 'Mahant Atul Upadhyay',
      description: 'Mahant Atul Upadhyay serves the temple with sincerity and devotion, conducting the sacred rituals with precision and love, ensuring every prayer offered here reaches the divine feet of Lord Ram.'
    },
    {
      role: 'Current Priest',
      emoji: '🌻',
      name: 'Mahant Anurag Upadhyay',
      description: 'With a heart full of bhakti, Mahant Anurag Upadhyay performs the sacred rites with deep reverence and ensures that the divine atmosphere of the mandir is maintained with purity and grace.'
    },
    {
      role: 'Current Priest',
      emoji: '🌷',
      name: 'Mahant Alok Upadhyay',
      description: 'Mahant Alok Upadhyay is a dedicated priest whose commitment to the rituals and traditions of the mandir helps keep the spiritual flame alive, welcoming every devotee with warmth and blessings.'
    }
  ];

  return (
    <section id="page-members" className="page-members">
      <PageHeader
        eyebrow="🙏 Seva • Service"
        title="Our"
        titleHighlight="Sacred Family"
        intro="Those who dedicate their lives to the seva of Lord Ram and Mata Janaki, keeping the lamp of dharma burning bright."
        containerClass="members-header"
      />

      <div className="members-grid">
        {/* Founder - spans full width */}
        <MemberCard member={founder} isFounder={true} />

        {/* Regular members */}
        {members.map((member, index) => (
          <MemberCard key={index} member={member} />
        ))}
      </div>
    </section>
  );
};

export default MembersPage;
